// merge URLs
const urls = [...new Set(
  items
    .map(item => item.json.url)
    .filter(Boolean)
)];

return [
  {
    json: {
      p_urls: urls
    }
  }
];

//create json object for each json string
return $input.all().map(item => {
  try {
    const parsedData = JSON.parse(item.json.output);

    return {
      json: parsedData
    };
  } catch (e) {
    return {
      json: { 
        error: "Parse error", 
        raw: item.json.output 
      }
    };
  }
});

// Helper to normalize URLs for comparison
const clean = (url) => {
  if (!url) return '';
  return url
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/\/$/, '')
    .trim();
};

// Input A: JSON parser node (has url, headline, snippet, published_date)
const itemsA = $('Start').first().json.Json_parser_allItems;

// Input B: If node (has source_url, url_exists)
// Reference it via $('If').all() or $node["If"].json depending on your n8n version
const itemsB = $('If').all();

// 1. Build a Set of cleaned source_urls from B (faster lookup than .includes)
const urlsInB = new Set(
  itemsB.map(item => clean(item.json.source_url))
);

// 2. Filter items from A where the cleaned url exists in B's source_urls
const matches = itemsA.filter(item => {
  const cleanedA = clean(item.json.url);
  return urlsInB.has(cleanedA);
});

// 3. Return matched items with ALL their original fields preserved
return matches.map(item => ({
  json: {
    ...item.json  // spreads: url, headline, snippet, published_date, etc.
  }
}));

